// Список нишевых поисковых запросов для VK groups.search.
// Расширяй по мере роста — это пробный набор.
const queries = [
  { niche: 'barber', q: 'барбершоп' },
  { niche: 'salon', q: 'салон красоты' },
  { niche: 'salon', q: 'парикмахерская' },
  { niche: 'cafe', q: 'кафе' },
  { niche: 'clinic', q: 'стоматология' },
  { niche: 'school', q: 'онлайн школа' },
];
return queries.map(o => ({ json: o }));

// Разворачиваем VK ответ в массив лидов с фильтрацией.
const niche = $('Build Queries').item.json.niche;
const body = $input.first().json;
if (body.error) throw new Error(`VK error: ${body.error.error_msg}`);
const items = (body.response && body.response.items) || [];
const out = [];
for (const g of items) {
  // Пропускаем закрытые/private и слишком мелкие группы
  if (g.is_closed && g.is_closed !== 0) continue;
  if ((g.members_count || 0) < 200) continue;
  // Минимум данных для контакта
  out.push({
    niche,
    external_id: String(g.id),
    title: g.name || g.screen_name || `vk_${g.id}`,
    url: `https://vk.com/${g.screen_name || ('club' + g.id)}`,
    members: g.members_count || null,
    city: g.city ? g.city.title : null,
    description: g.description || null,
    site: g.site || null,
    activity: g.activity || null,
  });
}
return out.map(j => ({ json: j }));
